import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

// Shared boilerplate for a valid file-store component setup
const STORE_COMPONENT = `
  namespace Components {
    @component(#{ type: ComponentType.Store })
    namespace TaskFileStore {
      @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
      namespace Storage {
        @mediaTypeHint("application/yaml")
        @storageObject(#{ path: "tasks.yaml" })
        model TaskRow { id: string; }
      }
    }
  }
`;

describe("@storage — one_per_store", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_storage
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.group_prefix_only:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_graph:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.group_prefix_only:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_in_store:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_graph:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_in_store:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_has_provider:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_graph:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_has_provider:must
  it("valid — single @storage in a Store component — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {}
      }
    `);
  });

  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.one_per_store:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_graph:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.one_per_store:must
  it("invalid — two @storage declarations in same Store component — storage-duplicate", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {}

        @storage(#{ provider: StorageProvider.filesystem, root: ".data2" })
        namespace Storage2 {}
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/storage-duplicate",
      message: /TaskFileStore/,
    });
  });
});

describe("@storageGroup — group_inside_storage", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_group
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_group:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.group_inside_storage:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_node:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.group_inside_storage:must
  it("valid — @storageGroup nested inside @storage namespace — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {
          @storageGroup(#{ prefix: "tasks" })
          namespace Tasks {}
        }
      }
    `);
  });

  it("invalid — @storageGroup not inside any @storage ancestor — invalid-namespace-nesting", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storageGroup(#{ prefix: "orphan" })
        namespace OrphanGroup {}
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
      message: /storageGroup/,
    });
  });
});

describe("@storage + @storageGroup — storage_xor_group", () => {
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_group:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_xor_group:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_node:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.storage_xor_group:must
  it("invalid — namespace carries both @storage and @storageGroup — storage-xor-group", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        @storageGroup(#{ prefix: "tasks" })
        namespace DualDecorated {}
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/storage-xor-group",
    });
  });

  it("valid — @storage and @storageGroup on different namespaces — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {
          @storageGroup(#{ prefix: "tasks" })
          namespace Tasks {}
        }
      }
    `);
  });
});

describe("@storageObject — no_path_collision", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_object
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_object:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.no_path_collision:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_predict:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.no_path_collision:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage_object:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.object_has_address:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_predict:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.object_has_address:must
  it("valid — two @storageObject models with distinct paths — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {
          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "tasks.yaml" })
          model TaskRow { id: string; }

          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "projects.yaml" })
          model ProjectRow { id: string; }
        }
      }
    `);
  });

  it("invalid — two @storageObject models resolving to the same path — storage-path-collision", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {
          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "items.yaml" })
          model TaskRow { id: string; }

          @mediaTypeHint("application/yaml")
          @storageObject(#{ path: "items.yaml" })
          model DuplicateRow { id: string; }
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/storage-path-collision",
      message: /items\.yaml/,
    });
  });

  it("invalid — two models in sub-groups resolving to same composed path — storage-path-collision", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Store })
      namespace Components.TaskFileStore {
        @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
        namespace Storage {
          @storageGroup(#{ prefix: "items" })
          namespace Group1 {
            @mediaTypeHint("application/yaml")
            @storageObject(#{ path: "record.yaml" })
            model RecordA { id: string; }
          }

          @storageGroup(#{ prefix: "items" })
          namespace Group2 {
            @mediaTypeHint("application/yaml")
            @storageObject(#{ path: "record.yaml" })
            model RecordB { id: string; }
          }
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/storage-path-collision",
      message: /items\/record\.yaml/,
    });
  });
});

// ─────────────────────────────────────────────────────────────────────────────
// path_refs_typed (storage-placeholder-unresolved)
// ─────────────────────────────────────────────────────────────────────────────

describe("@storageObject / @storage / @storageGroup — path_refs_typed", () => {
  describe("valid", () => {
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_storage:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.path_refs_typed:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_graph:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.path_refs_typed:must
    it("@storageObject path with no placeholders — zero diagnostics", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Store })
        namespace Components.TaskFileStore {
          @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
          namespace Storage {
            @mediaTypeHint("application/yaml")
            @storageObject(#{ path: "tasks.yaml" })
            model TaskRow { id: string; }
          }
        }
      `);
    });

    it("@storageObject path with placeholder resolving to a model in the component — zero diagnostics", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Store })
        namespace Components.TaskFileStore {
          model TaskPath { repoId: string; }

          @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
          namespace Storage {
            @mediaTypeHint("application/yaml")
            @storageObject(#{ path: "{@TaskPath.repoId}/tasks.yaml" })
            model TaskRow { content: string; }
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    it("@storageObject path with placeholder referencing unknown model — emits storage-placeholder-unresolved", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Store })
        namespace Components.TaskFileStore {
          @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
          namespace Storage {
            @mediaTypeHint("application/yaml")
            @storageObject(#{ path: "{@GhostModel.repoId}/tasks.yaml" })
            model TaskRow { id: string; }
          }
        }
      `);
      const diags = diagnostics.filter((d) => d.code === "@a10n/blueprint-typespec/storage-placeholder-unresolved");
      expectDiagnostics(diags, {
        code: "@a10n/blueprint-typespec/storage-placeholder-unresolved",
        message: /GhostModel/,
      });
    });
  });
});

